// Placeholder for the Mermaid bundle.
//
// RepoWeaver renders the hero banner and all charts as inline SVG on the server,
// so they never need a library. Mermaid diagrams (```mermaid fences) are the one
// visual that renders in the browser — this file is where the Mermaid bundle
// goes. It ships as a stub because this build environment's network allowlist
// blocks CDNs (the same constraint documented in ../charts.js), so the real
// bundle can't be fetched automatically.
//
// To enable client-side Mermaid rendering in the in-app Preview, drop the
// minified bundle here, replacing this file:
//
//   curl -fsSL https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.min.js \
//     -o web/static/js/vendor/mermaid.min.js
//
// Until then, Preview shows the raw diagram source (graceful degradation), and
// exported Markdown keeps ```mermaid fences that GitHub and most static-site
// generators render natively. No behavior here depends on this stub.
(function () {
  if (window && window.console && console.info) {
    console.info(
      "[RepoWeaver] Mermaid bundle not vendored; diagram source shown as-is. " +
      "See web/static/js/vendor/mermaid.min.js for setup."
    );
  }
})();
